'use client';

import Link from 'next/link';
import { 
  CalendarDays, 
  CheckSquare, 
  UserPlus, 
  FileWarning, 
  ArrowRight 
} from 'lucide-react';

interface ActivityItem {
  id: string;
  action: string;
  metadata: {
    detail: string;
    actor?: string;
    subject?: string;
    designation?: string;
    date?: string;
  };
  createdAt: string;
}

export default function ActivityPanel({ activities }: { activities: ActivityItem[] }) {
  const getRelativeTime = (isoString: string) => {
    const now = new Date();
    const date = new Date(isoString);
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.round(diffMs / (1000 * 60));
    const diffHours = Math.round(diffMs / (1000 * 60 * 60));
    const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24));

    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    return `${diffDays}d ago`;
  };

  const getActivityConfig = (action: string) => {
    switch (action) {
      case 'PAYROLL_PROCESSED':
        return {
          icon: CalendarDays,
          iconColor: 'text-emerald-600 dark:text-emerald-400',
          iconBg: 'bg-[#ecfdf5] dark:bg-emerald-950/40',
        };
      case 'LEAVE_APPROVED':
        return {
          icon: CheckSquare,
          iconColor: 'text-emerald-600 dark:text-emerald-400',
          iconBg: 'bg-[#ecfdf5] dark:bg-emerald-950/40',
        };
      case 'EMPLOYEE_ONBOARDED':
        return {
          icon: UserPlus,
          iconColor: 'text-blue-600 dark:text-blue-400',
          iconBg: 'bg-[#eff6ff] dark:bg-blue-950/40',
        };
      case 'TAX_UPDATE':
      default:
        return {
          icon: FileWarning,
          iconColor: 'text-amber-600 dark:text-amber-400',
          iconBg: 'bg-[#fffbeb] dark:bg-amber-950/40',
        };
    }
  };

  return (
    <div className="glass-card p-6 flex flex-col justify-between h-full hover:transform-none">
      {/* Header */}
      <div className="flex items-center justify-between mb-2">
        <div>
          <h3 className="text-base font-bold text-[var(--text-primary)]">Recent Activities</h3>
        </div>
      </div>

      {/* Row items list */}
      <div className="flex-1 divide-y divide-slate-100 dark:divide-slate-800/80">
        {activities.map((item) => {
          const config = getActivityConfig(item.action);
          const Icon = config.icon;
          
          return (
            <div 
              key={item.id}
              className="flex items-center justify-between py-4 group"
            >
              {/* Left details group: icon + text stack */}
              <div className="flex items-center gap-4 min-w-0">
                {/* Square Icon Badge */}
                <div className={`flex h-10 w-10 shrink-0 items-center justify-center rounded-xl ${config.iconBg} ${config.iconColor} transition-transform duration-200 group-hover:scale-105`}>
                  <Icon size={18} />
                </div>

                {/* Description text stack */}
                <div className="min-w-0">
                  <p className="text-sm font-semibold text-slate-800 dark:text-slate-200 transition-colors group-hover:text-blue-600 dark:group-hover:text-blue-400">
                    {item.metadata.detail}
                  </p>
                  <p className="text-xs text-slate-400 dark:text-slate-505 font-medium mt-0.5">
                    {item.metadata.actor && `By ${item.metadata.actor}`}
                    {item.metadata.subject && `${item.metadata.subject}`}
                    {item.metadata.designation && ` - ${item.metadata.designation}`}
                    {item.metadata.date && ` - ${item.metadata.date}`}
                  </p>
                </div>
              </div>

              {/* Right Relative Timestamp */}
              <span className="text-xs font-medium text-slate-400 dark:text-slate-500 whitespace-nowrap ml-4">
                {getRelativeTime(item.createdAt)}
              </span>
            </div>
          );
        })}
      </div>

      {/* View all footer */}
      <div className="mt-6 pt-4 border-t border-[var(--card-border)] text-right">
        <Link 
          href="/dashboard/reports"
          className="inline-flex items-center gap-1.5 text-xs font-bold text-blue-600 hover:text-blue-500 dark:text-blue-400 dark:hover:text-blue-300 hover:gap-2 transition-all animate-none"
        >
          View all activities
          <ArrowRight size={12} className="group-hover:translate-x-0.5 transition-transform" />
        </Link>
      </div>
    </div>
  );
}
