'use client';

import { Users, CalendarDays, Wallet, UserCheck } from 'lucide-react';

interface KpiData {
  totalEmployees: number;
  presentToday: number;
  monthlyPayroll: number;
  attendanceScore: number;
}

export default function KpiCards({ data }: { data: KpiData }) {
  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const cards = [
    {
      title: 'Total Employees',
      value: data.totalEmployees.toString(),
      icon: Users,
      iconBg: 'bg-[#eff6ff] text-[#2563eb] dark:bg-blue-950/40 dark:text-blue-400',
      trend: '↑ 8 this month',
    },
    {
      title: 'Present Today',
      value: data.presentToday.toString(),
      icon: CalendarDays,
      iconBg: 'bg-[#ecfdf5] text-[#10b981] dark:bg-emerald-950/40 dark:text-emerald-400',
      trend: `${Math.round((data.presentToday / data.totalEmployees) * 100)}% of total`,
    },
    {
      title: 'Monthly Payroll (May)',
      value: formatCurrency(data.monthlyPayroll),
      icon: Wallet,
      iconBg: 'bg-[#fffbeb] text-[#f59e0b] dark:bg-amber-950/40 dark:text-amber-400',
      trend: '↑ 6.4% vs last month',
    },
    {
      title: 'Attendance Score',
      value: `${data.attendanceScore}%`,
      icon: UserCheck,
      iconBg: 'bg-[#fff5f5] text-[#ef4444] dark:bg-rose-950/40 dark:text-rose-400',
      trend: '↑ 3.7% vs last month',
    },
  ];

  return (
    <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4 mb-8">
      {cards.map((card) => {
        const Icon = card.icon;
        
        return (
          <div
            key={card.title}
            className="bg-white dark:bg-slate-900 p-6 flex items-start gap-4 rounded-[20px] border border-slate-100 dark:border-slate-800/80 shadow-sm transition-all duration-200 hover:shadow-md"
          >
            {/* Left Circular Icon Badge */}
            <div className={`flex h-12 w-12 shrink-0 items-center justify-center rounded-full ${card.iconBg}`}>
              <Icon size={20} />
            </div>
            
            {/* Right Text Details Stack */}
            <div className="flex flex-col min-w-0">
              <span className="text-xs font-semibold text-slate-500 dark:text-slate-400">
                {card.title}
              </span>
              <h3 className="text-[26px] font-bold text-slate-900 dark:text-white tracking-tight leading-none mt-1">
                {card.value}
              </h3>
              <span className="text-xs font-medium text-emerald-600 dark:text-emerald-400 mt-1.5">
                {card.trend}
              </span>
            </div>
          </div>
        );
      })}
    </div>
  );
}
