'use client';

import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';

interface TrendItem {
  month: string;
  gross: number;
  net: number;
  deductions: number;
}

interface TrendChartProps {
  data: TrendItem[];
  totals: {
    gross: number;
    deductions: number;
    net: number;
    avg: number;
  };
}

export default function TrendChart({ data, totals }: TrendChartProps) {
  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const formatLakhs = (val: number) => {
    if (val === 0) return '₹0';
    return `₹${(val / 100000).toFixed(0)}L`;
  };

  const formatMonthTick = (monthStr: string) => {
    if (!monthStr || !monthStr.includes('-')) return monthStr;
    const [year, month] = monthStr.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1, 1);
    return date.toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
  };

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="rounded-xl border border-slate-200 dark:border-slate-800 bg-white/95 dark:bg-slate-950/95 p-3.5 shadow-xl backdrop-blur-md z-50">
          <p className="text-[9px] font-bold text-[var(--text-muted)] mb-1.5 uppercase tracking-wider">{formatMonthTick(payload[0].payload.month)}</p>
          <div className="space-y-1">
            <div className="flex items-center gap-6 justify-between">
              <span className="text-[11px] text-[var(--text-secondary)] font-semibold">Gross Payroll:</span>
              <span className="text-xs font-black text-blue-600 dark:text-blue-400">{formatCurrency(payload[0].value)}</span>
            </div>
            <div className="flex items-center gap-6 justify-between">
              <span className="text-[11px] text-[var(--text-secondary)] font-semibold">Net Payroll:</span>
              <span className="text-xs font-black text-emerald-600 dark:text-emerald-400">{formatCurrency(payload[0].payload.net)}</span>
            </div>
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="glass-card p-6 flex flex-col justify-between h-full hover:transform-none">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h3 className="text-base font-bold text-[var(--text-primary)]">Payroll Trend</h3>
        </div>
        <select className="text-xs font-semibold rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] px-3 py-1.5 focus:outline-none focus:border-blue-500/50">
          <option>Last 6 Months</option>
        </select>
      </div>

      {/* Recharts Area Chart */}
      <div className="w-full h-64 min-h-[250px]">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart
            data={data}
            margin={{ top: 10, right: 10, left: -20, bottom: 0 }}
          >
            <defs>
              <linearGradient id="colorGross" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.15}/>
                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0.0}/>
              </linearGradient>
            </defs>
            <CartesianGrid 
              strokeDasharray="3 3" 
              vertical={false} 
              stroke="var(--card-border)" 
              opacity={0.5}
            />
            <XAxis 
              dataKey="month" 
              axisLine={false}
              tickLine={false}
              tick={{ fontSize: 10, fill: 'var(--text-muted)', fontWeight: 500 }}
              tickFormatter={formatMonthTick}
              dy={10}
            />
            <YAxis 
              axisLine={false}
              tickLine={false}
              tick={{ fontSize: 10, fill: 'var(--text-muted)', fontWeight: 500 }}
              tickFormatter={formatLakhs}
              domain={[0, 6000000]}
              ticks={[0, 1500000, 3000000, 4500000, 6000000]}
            />
            <Tooltip content={<CustomTooltip />} />
            <Area 
              type="monotone" 
              dataKey="gross" 
              stroke="#3b82f6" 
              strokeWidth={2}
              fillOpacity={1} 
              fill="url(#colorGross)" 
              dot={{ r: 4, stroke: '#3b82f6', strokeWidth: 2, fill: '#fff' }}
              activeDot={{ r: 6, stroke: '#3b82f6', strokeWidth: 2, fill: '#fff' }}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>

      {/* Stats Footer Row - Clean partitioned columns matching reference */}
      <div className="grid grid-cols-2 md:grid-cols-4 mt-6 pt-6 border-t border-slate-100 dark:border-slate-800 gap-y-4 md:gap-y-0">
        <div className="flex flex-col pr-4 border-r border-slate-100 dark:border-slate-800">
          <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Total Payroll</span>
          <p className="text-base font-bold text-slate-800 dark:text-slate-100 mt-0.5">{formatCurrency(totals.gross)}</p>
        </div>
        <div className="flex flex-col pl-4 pr-4 md:border-r border-slate-100 dark:border-slate-800">
          <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Total Deductions</span>
          <p className="text-base font-bold text-slate-800 dark:text-slate-100 mt-0.5">{formatCurrency(totals.deductions)}</p>
        </div>
        <div className="flex flex-col pr-4 md:pl-4 border-r border-slate-100 dark:border-slate-800">
          <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Net Payroll</span>
          <p className="text-base font-bold text-slate-800 dark:text-slate-100 mt-0.5">{formatCurrency(totals.net)}</p>
        </div>
        <div className="flex flex-col pl-4">
          <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Avg. Payroll / Employee</span>
          <p className="text-base font-bold text-slate-800 dark:text-slate-100 mt-0.5">{formatCurrency(totals.avg)}</p>
        </div>
      </div>
    </div>
  );
}
