'use client';

import { useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Sector } from 'recharts';

const PieComponent = Pie as any;

interface BreakdownData {
  basic: number;
  allowances: number;
  deductions: number;
  bonus: number;
}

interface BreakdownChartProps {
  data: BreakdownData;
  total: number;
}

export default function BreakdownChart({ data, total }: BreakdownChartProps) {
  const [activeIndex, setActiveIndex] = useState(-1);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const chartData = [
    { name: 'Basic Salary', value: data.basic, color: '#3b82f6', percent: '45.4%' },
    { name: 'Allowances', value: data.allowances, color: '#10b981', percent: '25.5%' },
    { name: 'Deductions', value: data.deductions, color: '#f43f5e', percent: '14.8%' },
    { name: 'Bonus & Others', value: data.bonus, color: '#fbbf24', percent: '14.2%' },
  ];

  const renderActiveShape = (props: any) => {
    const { cx, cy, innerRadius, outerRadius, startAngle, endAngle, fill } = props;
    return (
      <g>
        <Sector
          cx={cx}
          cy={cy}
          innerRadius={innerRadius - 2}
          outerRadius={outerRadius + 4}
          startAngle={startAngle}
          endAngle={endAngle}
          fill={fill}
        />
      </g>
    );
  };

  return (
    <div className="glass-card p-6 flex flex-col justify-between h-full hover:transform-none">
      {/* Header */}
      <div>
        <h3 className="text-base font-bold text-[var(--text-primary)]">Payroll Breakdown (May)</h3>
      </div>

      {/* Donut Chart & Legend */}
      <div className="flex flex-col sm:flex-row lg:flex-col xl:flex-row items-center justify-center gap-6 mt-6">
        {/* Recharts Pie Chart (Donut) */}
        <div className="relative w-44 h-44 shrink-0">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <PieComponent
                activeIndex={activeIndex}
                activeShape={renderActiveShape}
                data={chartData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={76}
                paddingAngle={3}
                dataKey="value"
                onMouseEnter={(e: any, index: number) => setActiveIndex(index)}
                onMouseLeave={() => setActiveIndex(-1)}
              >
                {chartData.map((entry, index) => (
                  <Cell 
                    key={`cell-${index}`} 
                    fill={entry.color} 
                    style={{ outline: 'none' }}
                  />
                ))}
              </PieComponent>
            </PieChart>
          </ResponsiveContainer>
          
          {/* Central Total text (Value on top, Total below) */}
          <div className="absolute inset-0 flex flex-col items-center justify-center text-center pointer-events-none">
            <span className="text-base font-bold text-slate-800 dark:text-slate-100">
              {formatCurrency(total)}
            </span>
            <span className="text-[10px] font-semibold text-slate-400 dark:text-slate-500 uppercase tracking-wider mt-0.5">
              Total
            </span>
          </div>
        </div>

        {/* Custom Legend - Stacked layout next to color bullets */}
        <div className="flex-1 space-y-3 w-full pl-0 xl:pl-4">
          {chartData.map((item, index) => {
            const isHovered = activeIndex === index;
            return (
              <div 
                key={item.name}
                onMouseEnter={() => setActiveIndex(index)}
                onMouseLeave={() => setActiveIndex(-1)}
                className={`flex items-start gap-3 p-1.5 rounded-xl transition-all duration-200 cursor-pointer
                  ${isHovered ? 'bg-blue-50/50 dark:bg-blue-950/10' : 'hover:bg-slate-50/50 dark:hover:bg-slate-800/30'}
                `}
              >
                {/* Color Bullet Dot */}
                <span 
                  className="h-3 w-3 rounded-full mt-1 shrink-0" 
                  style={{ backgroundColor: item.color }}
                ></span>
                
                {/* Details Text Block */}
                <div className="flex flex-col min-w-0">
                  <p className={`text-sm font-semibold transition-colors ${isHovered ? 'text-blue-600 dark:text-blue-400' : 'text-slate-800 dark:text-slate-200'}`}>
                    {item.name}
                  </p>
                  <p className="text-xs text-slate-500 dark:text-slate-400 font-medium mt-0.5">
                    {formatCurrency(item.value)} ({item.percent})
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
