'use client';

import { useEffect, useState } from 'react';
import HeroSection from '@/components/dashboard/HeroSection';
import KpiCards from '@/components/dashboard/KpiCards';
import TrendChart from '@/components/dashboard/TrendChart';
import BreakdownChart from '@/components/dashboard/BreakdownChart';
import ActivityPanel from '@/components/dashboard/ActivityPanel';
import { apiClient } from '@/lib/api-client';

interface DashboardData {
  kpi: {
    totalEmployees: number;
    presentToday: number;
    monthlyPayroll: number;
    netPayroll: number;
    totalDeductions: number;
    attendanceScore: number;
  };
  breakdown: {
    basic: number;
    allowances: number;
    deductions: number;
    bonus: number;
  };
  trend: any[];
  activities: any[];
}

export default function DashboardOverviewPage() {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    apiClient.get('/api/dashboard/stats?month=2026-05')
      .then((res) => {
        if (res.success) {
          setData(res.data);
        } else {
          setError(res.message || 'Failed to load stats');
        }
      })
      .catch((err) => {
        setError(err.message || 'An error occurred fetching dashboard data');
      })
      .finally(() => {
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="flex flex-col gap-6 animate-pulse">
        {/* Banner skeleton */}
        <div className="h-44 w-full rounded-2xl bg-slate-200 dark:bg-slate-800"></div>
        {/* KPI grid skeleton */}
        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
          <div className="h-28 rounded-2xl bg-slate-200 dark:bg-slate-800"></div>
          <div className="h-28 rounded-2xl bg-slate-200 dark:bg-slate-800"></div>
          <div className="h-28 rounded-2xl bg-slate-200 dark:bg-slate-800"></div>
          <div className="h-28 rounded-2xl bg-slate-200 dark:bg-slate-800"></div>
        </div>
        {/* Charts row skeleton */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 h-96 rounded-2xl bg-slate-200 dark:bg-slate-800"></div>
          <div className="lg:col-span-1 h-96 rounded-2xl bg-slate-200 dark:bg-slate-800"></div>
        </div>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="rounded-2xl border border-red-200 bg-red-50 dark:bg-red-950/20 dark:border-red-900/30 p-6 text-center">
        <h3 className="text-sm font-bold text-red-800 dark:text-red-400">Unable to load dashboard</h3>
        <p className="text-xs text-red-600 dark:text-red-400/80 mt-1">{error || 'Unknown error'}</p>
        <button 
          onClick={() => window.location.reload()}
          className="mt-4 px-4 py-2 text-xs font-semibold text-white bg-blue-600 rounded-xl hover:bg-blue-500 transition-colors"
        >
          Try Again
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-8">
      {/* 1. Welcome Card Banner */}
      <HeroSection />

      {/* 2. Reusable KPI Statistics grid */}
      <KpiCards data={data.kpi} />

      {/* 3. Analytics Charts Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2">
          <TrendChart 
            data={data.trend} 
            totals={{
              gross: data.kpi.monthlyPayroll,
              deductions: data.kpi.totalDeductions,
              net: data.kpi.netPayroll,
              avg: Math.round(data.kpi.monthlyPayroll / data.kpi.totalEmployees),
            }}
          />
        </div>
        <div className="lg:col-span-1">
          <BreakdownChart 
            data={data.breakdown} 
            total={data.kpi.monthlyPayroll}
          />
        </div>
      </div>

      {/* 4. Timeline list panel */}
      <div className="w-full">
        <ActivityPanel activities={data.activities} />
      </div>
    </div>
  );
}
